// Item catalog by MCC — goods/services for Invoice + Payment Link forms.
// Each MCC has 8 name variants per price point. Business picks its 50 items
// deterministically via profile_id hash → different businesses on same MCC
// see different names at identical prices. All 22 required prices hit:
//   17,18,19,30,35,40,45,49,50,75,95,99,120,150,175,200,250,295,350,399,450,499
// + 28 more filling $17–$499.

// djb2 hash — stable across browsers/sessions
function hashProfile(pid) {
  const s = String(pid || 'default');
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) | 0;
  return Math.abs(h);
}

