// ── Public API ──────────────────────────────────────────────────────
function getItemsForMcc(mcc, profileId) {
  if (!mcc) return [];
  const key = String(mcc).padStart(4, '0');
  const pool = ITEM_CATALOG[key] || ITEM_CATALOG[String(mcc)];
  if (!pool) return [];
  const hash = hashProfile(profileId);
  return CATALOG_PRICES
    .filter(p => pool[p] && pool[p].length > 0)
    .map(price => {
      const variants = pool[price];
      return { name: variants[hash % variants.length], price };
    });
}

// Helper for dropdown: count how many items an MCC has
function getCatalogSize(mcc) {
  const key = String(mcc).padStart(4, '0');
  const pool = ITEM_CATALOG[key] || ITEM_CATALOG[String(mcc)];
  if (!pool) return 0;
  return CATALOG_PRICES.filter(p => pool[p] && pool[p].length > 0).length;
}
